action.command:
cat > /tmp/groupshared_interface_repro.sh <<'EOF'
#!/usr/bin/env bash
SLANGC="${SLANGC:-/workspace/slang/build/Release/bin/slangc}"
WORKDIR="${TMPDIR:-/tmp}/slang-groupshared-iface-$$"
mkdir -p "$WORKDIR"

cat > "$WORKDIR/direct.slang" <<'SLANG'
interface IFoo
{
    float getValue();
}

struct ImplA : IFoo
{
    float v;
    float getValue() { return v; }
}

groupshared IFoo sharedVal;
RWStructuredBuffer<float> outputBuffer;

[numthreads(64, 1, 1)]
void computeMain(uint3 tid : SV_DispatchThreadID)
{
    if (tid.x == 0)
        sharedVal = ImplA(42.0);
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[tid.x] = sharedVal.getValue();
}
SLANG

cat > "$WORKDIR/array.slang" <<'SLANG'
interface IFoo
{
    float getValue();
}

struct ImplA : IFoo
{
    float v;
    float getValue() { return v; }
}

groupshared IFoo sharedVals[4];
RWStructuredBuffer<float> outputBuffer;

[numthreads(64, 1, 1)]
void computeMain(uint3 tid : SV_DispatchThreadID)
{
    if (tid.x == 0)
        sharedVals[0] = ImplA(42.0);
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[tid.x] = sharedVals[0].getValue();
}
SLANG

cat > "$WORKDIR/wrapped.slang" <<'SLANG'
interface IFoo
{
    float getValue();
}

struct ImplA : IFoo
{
    float v;
    float getValue() { return v; }
}

struct Wrapper
{
    IFoo member;
}

groupshared Wrapper sharedVal;
RWStructuredBuffer<float> outputBuffer;

[numthreads(64, 1, 1)]
void computeMain(uint3 tid : SV_DispatchThreadID)
{
    if (tid.x == 0)
        sharedVal.member = ImplA(42.0);
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[tid.x] = sharedVal.member.getValue();
}
SLANG

status=0
for file in direct array wrapped; do
    for target in spirv hlsl; do
        echo "=== $file target=$target ==="
        "$SLANGC" "$WORKDIR/$file.slang" -target "$target" -stage compute -entry computeMain -o /dev/null > "$WORKDIR/$file.$target.out" 2>&1
        code=$?
        cat "$WORKDIR/$file.$target.out"
        echo "exit=$code"
        if grep -q "internal error\|error 99999\|InternalError\|unexpected IR opcode\|Unhandled local inst" "$WORKDIR/$file.$target.out"; then
            status=99
        elif [ "$file" = "wrapped" ] && [ $code -ne 0 ]; then
            status=1
        fi
    done
done

rm -rf "$WORKDIR"
exit $status
EOF
chmod +x /tmp/groupshared_interface_repro.sh
/tmp/groupshared_interface_repro.sh

