action.command:
cat > /tmp/groupshared_interface_repro.sh <<'EOF'
#!/usr/bin/env bash
SLANGC="${SLANGC:-/workspace/slang/build/Release/bin/slangc}"
WORKDIR="${TMPDIR:-/tmp}/slang-groupshared-iface-$$"
mkdir -p "$WORKDIR"

COMMON='interface IFoo
{
    float getValue();
}

struct ImplA : IFoo
{
    float v;
    float getValue() { return v; }
}

RWStructuredBuffer<float> outputBuffer;
'

cat > "$WORKDIR/direct.slang" <<SLANG
$COMMON
groupshared IFoo sharedVal;

[numthreads(64, 1, 1)]
void computeMain(uint3 tid : SV_DispatchThreadID)
{
    if (tid.x == 0)
        sharedVal = ImplA(42.0);
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[tid.x] = sharedVal.getValue();
}
SLANG

cat > "$WORKDIR/array.slang" <<SLANG
$COMMON
groupshared IFoo sharedVals[4];

[numthreads(64, 1, 1)]
void computeMain(uint3 tid : SV_DispatchThreadID)
{
    if (tid.x == 0)
        sharedVals[0] = ImplA(42.0);
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[tid.x] = sharedVals[0].getValue();
}
SLANG

cat > "$WORKDIR/multiarray.slang" <<SLANG
