status=0
for file in direct array multiarray wrapped wrappedarray; do
    for target in spirv hlsl; do
        echo "=== $file target=$target ==="
        "$SLANGC" "$WORKDIR/$file.slang" -target "$target" -stage compute -entry computeMain -o "$WORKDIR/$file.$target.bin" > "$WORKDIR/$file.$target.out" 2>&1
        code=$?
        cat "$WORKDIR/$file.$target.out"
        echo "exit=$code"
        if grep -q "internal error\|error 99999\|E99999\|E99997\|InternalError\|unexpected IR opcode\|Unhandled local inst" "$WORKDIR/$file.$target.out"; then
            echo "unexpected ICE for $file $target"
            status=99
        elif [ "$file" = "wrapped" ] || [ "$file" = "wrappedarray" ]; then
            if [ $code -ne 0 ]; then
                echo "expected wrapper case to compile for $target"
                status=1
