content.text:
// Direct groupshared variables with interface types currently trigger an
// ICE because the existential lowering passes do not handle groupshared-rate
// variables. The existential layout is known after compilation, so this may
// be a fixable limitation rather than a fundamental incompatibility.
// Disabled until the fix lands. See https://github.com/shader-slang/slang/issues/10144
//
// The struct-wrapping workaround is validated by
// groupshared-struct-with-interface.slang.

// --- Scenario 1: Direct groupshared interface variable ---
//DISABLE_TEST:SIMPLE(filecheck=CHK1): -target spirv -stage compute -entry scenario1
//DISABLE_TEST:SIMPLE(filecheck=CHK1): -target hlsl -stage compute -entry scenario1

interface IValue
{
    float get();
}

struct ScalarValue : IValue
{
    float v;
    float get() { return v; }
}

struct DoubleValue : IValue
{
    float v;
    float get() { return v * 2.0; }
}

groupshared IValue sharedVal;

RWStructuredBuffer<float> outputBuffer;

[numthreads(64, 1, 1)]
void scenario1(uint3 tid : SV_DispatchThreadID)
{
    if (tid.x == 0)
        sharedVal = ScalarValue(42.0);
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[tid.x] = sharedVal.get();
}

// --- Scenario 2: Groupshared array of interface-typed values ---
//DISABLE_TEST:SIMPLE(filecheck=CHK2): -target spirv -stage compute -entry scenario2
//DISABLE_TEST:SIMPLE(filecheck=CHK2): -target hlsl -stage compute -entry scenario2

groupshared IValue sharedArray[4];

[numthreads(4, 1, 1)]
void scenario2(uint3 tid : SV_DispatchThreadID)
{
    if (tid.x < 2)
        sharedArray[tid.x] = ScalarValue(float(tid.x));
    else
        sharedArray[tid.x] = DoubleValue(float(tid.x));
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[tid.x] = sharedArray[tid.x].get();
}

--- wrapper ---
// Groupshared memory containing a struct with an interface-typed field.
//
// Unlike a bare `groupshared IFoo`, wrapping the interface in a struct
// allows the existential lowering to produce a fixed-size tuple (type tag
// + AnyValue) inside the struct before the groupshared allocation is
// finalized. This test verifies that dynamic dispatch through a
// groupshared struct's interface member works correctly at runtime.

//TEST(compute):COMPARE_COMPUTE_EX(filecheck-buffer=CHECK):-dx12 -compute -shaderobj -output-using-type
//TEST(compute, vulkan):COMPARE_COMPUTE_EX(filecheck-buffer=CHECK):-vk -compute -shaderobj -output-using-type
//TEST(compute):COMPARE_COMPUTE_EX(filecheck-buffer=CHECK):-cuda -compute -shaderobj -output-using-type
//TEST(compute):COMPARE_COMPUTE_EX(filecheck-buffer=CHECK):-mtl -compute -shaderobj -output-using-type

//DIAGNOSTIC_TEST:SIMPLE(diag=REPORT,non-exhaustive):-target hlsl -stage compute -entry computeMain -report-dynamic-dispatch-sites

//TEST_INPUT:ubuffer(data=[0 0 0 0], stride=4):out,name=outputBuffer
RWStructuredBuffer<float> outputBuffer;

interface ITransform
{
    float apply(float x);
}

struct Identity : ITransform
{
    float apply(float x) { return x; }
}

struct Doubler : ITransform
{
    float scale;
    float apply(float x) { return x * scale; }
}

struct SharedState
{
    ITransform transform;
    float baseValue;
}

groupshared SharedState state;

[numthreads(1, 1, 1)]
void computeMain(uint3 tid : SV_DispatchThreadID)
{
    state.baseValue = 10.0;
    state.transform = Identity();
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[0] = state.transform.apply(state.baseValue);
//REPORT: generated dynamic dispatch code for this site. 2 possible types
    // CHECK: 10.0

    state.transform = Doubler(3.0);
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[1] = state.transform.apply(state.baseValue);
    // CHECK: 30.0

    state.baseValue = 5.0;
    state.transform = Identity();
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[2] = state.transform.apply(state.baseValue);
    // CHECK: 5.0

    state.transform = Doubler(4.0);
    GroupMemoryBarrierWithGroupSync();
    outputBuffer[3] = state.transform.apply(state.baseValue);
    // CHECK: 20.0
}

